1	//! Reconstructing how a record cell's flat term text is fed through the layout
2	//! engine ([`crate::pretty`]).
3	//!
4	//! The engine ([`crate::pretty`]) is the reference toolchain's BSD pretty-printer,
5	//! ported faithfully. This module carries the tamarin-SPECIFIC part: which
6	//! combinators wrap a fact / tuple / info cell, with what padding, and at what
7	//! line width — every one of which was pinned by black-box probes (BEHAVIOR.md
8	//! §3f; QUERIES.log wrap sweeps E10..E14 / W69..W74 and the Wide-rule case graph).
9	//!
10	//! Reconstructed cell grammar (each byte-verified against captured fixtures):
11	//!   * **fact / relation cell** `Name( a, b, … )` — the arguments are laid out as
12	//!     a `fsep` (paragraph fill, comma-punctuated) that opens after `Name( ` and
13	//!     self-aligns its continuation lines to that column; the whole thing is an
14	//!     outer `sep [ Name( args , ) ]` so the closing `)` drops to column 0 on its
15	//!     own line exactly when the argument fill wrapped (the ` )` padding space is
16	//!     the break). Zero-argument facts render `Name( )` flat.
17	//!   * **tuple** `<e1, …, en>` — `'<' <> fcat(e1, ", ", …, en, nest(-1) '>')`: the
18	//!     elements fill (paragraph, `, `-punctuated) and self-align one column past
19	//!     the `<`; the closing `>` is a fill element nested back one column, so it
20	//!     stays beside the last element when it fits and otherwise peels onto its own
21	//!     line aligned under the `<`.
22	//!   * **info cell** `#t : Rule[a1, …]` — the action list is a `vcat` (one action
23	//!     per line) wrapped in `[ … ]`; with two or more actions it is therefore
24	//!     always vertical, and a lone action fills only when the cell overflows.
25	//!
26	//! The fit **budget** a cell is laid out at is the HughesPJ *ribbon*; for a lone
27	//! cell it is [`FILL_WIDTH`] (= 87, the probed flat-fit boundary). The line length
28	//! is `1.5 ×` the ribbon ([`RIBBONS`] = 1.5, the HughesPJ default), and that gap
29	//! is what makes `fill` produce *ragged* paragraph fills — a physical line may be
30	//! shorter than a later one (e.g. two arguments then four wider ones) — which a
31	//! greedy fill can never do and which the reference's output requires (see
32	//! [`budget_line_len`] and the `ragged_fill_line0_shorter_than_line1` test). How
33	//! the cells of one record group share the budget is a separate, probe-derived
34	//! proportional allocation and lives in [`crate::generate::group_widths`].
35	
36	use crate::pretty::{beside_op, char as pchar, fcat, fsep, nest, render_page, sep, text, vcat, Doc};
37	
38	/// The fit **budget** (ribbon) the reference lays a lone record cell out at
39	/// (BEHAVIOR.md §3f): a fact whose flat rendering is `≤ 87` columns stays on one
40	/// line, `88` breaks. A record group shares this budget among its cells
41	/// (`crate::generate`); this is the per-cell budget of a *lone* cell.
42	pub const FILL_WIDTH: isize = 87;
43	
44	/// Ribbons-per-line the reference uses for cell layout (HughesPJ default). The
45	/// probed flat-fit boundary is the **ribbon** (content width excluding
46	/// indentation), and the line length is `1.5 ×` the ribbon — a gap that is what
47	/// makes HughesPJ `fill` produce *ragged* paragraph fills (a physical line may be
48	/// shorter than a later one, e.g. `2` args then `4` wider args), the reference's
49	/// observed behavior. A cell's budget `B` is its ribbon; it is rendered at line
50	/// length [`budget_line_len`]`(B)` so `round(lineLen / 1.5) == B`.
51	pub const RIBBONS: f64 = 1.5;
52	
53	/// The HughesPJ line length that yields ribbon (= fit budget) `budget` at
54	/// [`RIBBONS`] = 1.5: `lineLen = ⌊3·budget / 2⌋`, so `round(lineLen / 1.5) ==
55	/// budget`. Content still fits in `budget` columns, but the wider line length
56	/// gives `fill` room to look ahead and produce ragged fills.
57	pub fn budget_line_len(budget: isize) -> isize {
58	    3 * budget / 2
59	}
