61	/// Split `s` at top-level `", "` separators, honoring `()`/`<>`/`[]` nesting and
62	/// `'…'` quotes. Returns the comma-separated pieces (each un-trimmed).
63	pub fn split_top_commas(s: &str) -> Vec<String> {
64	    let chars: Vec<char> = s.chars().collect();
65	    let mut parts: Vec<String> = Vec::new();
66	    let mut cur = String::new();
67	    let mut depth = 0i32;
68	    let mut in_quote = false;
69	    let mut i = 0;
70	    while i < chars.len() {
71	        let c = chars[i];
72	        if in_quote {
73	            cur.push(c);
74	            if c == '\'' {
75	                in_quote = false;
76	            }
77	            i += 1;
78	            continue;
79	        }
80	        match c {
81	            '\'' => {
82	                in_quote = true;
83	                cur.push(c);
84	                i += 1;
85	            }
86	            '(' | '<' | '[' => {
87	                depth += 1;
88	                cur.push(c);
89	                i += 1;
90	            }
91	            ')' | '>' | ']' => {
92	                depth -= 1;
93	                cur.push(c);
94	                i += 1;
95	            }
96	            ',' if depth == 0 && i + 1 < chars.len() && chars[i + 1] == ' ' => {
97	                parts.push(std::mem::take(&mut cur));
98	                i += 2;
99	            }
100	            _ => {
101	                cur.push(c);
102	                i += 1;
103	            }
104	        }
105	    }
106	    parts.push(cur);
107	    parts
108	}
