110	/// Count top-level actions in an info action list `#t : Rule[ … ]` (0 if none).
111	pub fn count_info_actions(flat: &str) -> usize {
112	    let Some(open) = flat.find('[') else { return 0 };
113	    let inner = &flat[open + 1..];
114	    let inner = inner.strip_suffix(']').unwrap_or(inner);
115	    if inner.is_empty() {
116	        return 0;
117	    }
118	    split_top_commas(inner).len()
119	}
