121	fn is_tuple(s: &str) -> bool {
122	    s.starts_with('<') && s.ends_with('>') && s.len() >= 2
123	}
124	
125	/// A `Doc` for one tuple element / fact argument. Tuples recurse; every other
126	/// shape (atom, function application, exponentiation, AC term) is a single fill
127	/// token rendered from its flat text (these do not re-wrap internally in the
128	/// observed cells — the wrap happens at the enclosing fact/tuple level).
129	fn arg_doc(s: &str) -> Doc {
130	    if is_tuple(s) {
131	        tuple_doc(&s[1..s.len() - 1])
132	    } else {
133	        text(s)
134	    }
135	}
136	
137	/// `<e1, …, en>` — the elements fill and align one past the `<`; the `>` is a
138	/// fill element nested back one column so it stays beside the last element when
139	/// it fits and peels under the `<` otherwise.
140	fn tuple_doc(inner: &str) -> Doc {
141	    let elems = split_top_commas(inner);
142	    let n = elems.len();
143	    let mut toks: Vec<Doc> = Vec::with_capacity(n + 1);
144	    for (i, e) in elems.iter().enumerate() {
145	        let d = arg_doc(e);
146	        if i + 1 < n {
147	            toks.push(beside_op(d, text(", ")));
148	        } else {
149	            toks.push(d);
150	        }
151	    }
152	    toks.push(nest(-1, &pchar('>')));
153	    beside_op(pchar('<'), fcat(toks))
154	}
155	
156	/// `Name( a, b, … )` — the argument list is a comma-punctuated `fsep` opening
157	/// after `Name( `; the outer `sep [ …, ) ]` drops the closing `)` to its own line
158	/// exactly when the argument fill wraps.
159	fn fact_doc(name: &str, args: &[String]) -> Doc {
160	    if args.is_empty() {
161	        return text(&format!("{}( )", name));
162	    }
163	    let n = args.len();
164	    let toks: Vec<Doc> = args
165	        .iter()
166	        .enumerate()
167	        .map(|(i, a)| {
168	            let d = arg_doc(a);
169	            if i + 1 < n {
170	                beside_op(d, text(","))
171	            } else {
172	                d
173	            }
174	        })
175	        .collect();
176	    let args_doc = fsep(toks);
177	    let opened = beside_op(text(&format!("{}( ", name)), args_doc);
178	    sep(vec![opened, text(")")])
179	}
180	
181	/// `#t : Rule[a1, …]` — the action list is a `vcat` (one action per line) inside
182	/// `[ … ]`; `#t : Rule` with no actions is bare text.
183	fn info_doc(flat: &str) -> Doc {
184	    let Some(open) = flat.find('[') else {
185	        return text(flat);
186	    };
187	    if !flat.ends_with(']') {
188	        return text(flat);
189	    }
190	    let prefix = &flat[..open + 1]; // "#t : Rule["
191	    let inner = &flat[open + 1..flat.len() - 1];
192	    let actions = split_top_commas(inner);
193	    let n = actions.len();
194	    let action_docs: Vec<Doc> = actions
195	        .iter()
196	        .enumerate()
197	        .map(|(i, a)| {
198	            // Each action is a fact that may itself fill-wrap; non-final actions
199	            // carry a trailing comma.
200	            let d = fact_from_flat(a);
201	            if i + 1 < n {
202	                beside_op(d, text(","))
203	            } else {
204	                d
205	            }
206	        })
207	        .collect();
208	    beside_op(beside_op(text(prefix), vcat(action_docs)), text("]"))
209	}
