211	/// Build a fact `Doc` from a flat fact string `Name( … )` (or a bare atom).
212	fn fact_from_flat(flat: &str) -> Doc {
213	    if let Some((name, args)) = parse_fact(flat) {
214	        fact_doc(name, &args)
215	    } else {
216	        text(flat)
217	    }
218	}
219	
220	/// Parse a padded fact `Name( a, b )` / `Name( )` into `(name, args)`. Returns
221	/// `None` for anything that is not a padded fact (an atom, a function `f(x)`
222	/// without inner padding, etc.).
223	fn parse_fact(flat: &str) -> Option<(&str, Vec<String>)> {
224	    if flat == "" {
225	        return None;
226	    }
227	    // Zero-arg: "Name( )"
228	    if let Some(name) = flat.strip_suffix("( )") {
229	        if !name.is_empty() && !name.contains(['(', ')', '<', '>', ' ']) {
230	            return Some((name, Vec::new()));
231	        }
232	    }
233	    let open = flat.find("( ")?;
234	    if !flat.ends_with(" )") {
235	        return None;
236	    }
237	    let name = &flat[..open];
238	    // The name must be a plain relation/fact symbol (optionally `!`-prefixed).
239	    if name.is_empty()
240	        || name.contains(['(', ')', '<', '>', ' ', ','])
241	    {
242	        return None;
243	    }
244	    let content = &flat[open + 2..flat.len() - 2];
245	    Some((name, split_top_commas(content)))
246	}
