248	/// Build a `Doc` for one record cell from its flat (post-abbreviation,
249	/// un-escaped) text, dispatching by cell shape (info / fact / atom).
250	pub fn cell_doc(flat: &str) -> Doc {
251	    if flat.starts_with('#') && flat.contains('[') {
252	        info_doc(flat)
253	    } else if let Some((name, args)) = parse_fact(flat) {
254	        fact_doc(name, &args)
255	    } else {
256	        text(flat)
257	    }
258	}
