260	/// Render a cell's flat text to physical lines `(indent, content)` at the given
261	/// fit **budget** (ribbon), via the layout engine. `indent` is the count of
262	/// leading spaces the engine emitted (→ `&nbsp;` in the record label); `content`
263	/// is the line with that indentation stripped, still un-escaped. The cell fits on
264	/// one line iff its flat width ≤ `budget`; the line length is
265	/// [`budget_line_len`]`(budget)` (= 1.5·budget) so wrapping is ragged (§3f).
266	pub fn layout_lines(flat: &str, budget: isize) -> Vec<(usize, String)> {
267	    layout_lines_lr(flat, budget_line_len(budget), RIBBONS)
268	}
269	
270	/// Like [`layout_lines`] but with an explicit `line_len` and `ribbons_per_line`
271	/// (ribbon = round(line_len / ribbons_per_line)). When `line_len` exceeds the
272	/// ribbon, HughesPJ `fill` produces ragged paragraph fills (a physical line may
273	/// be shorter than a later one), the reference's observed behavior.
274	pub fn layout_lines_lr(flat: &str, line_len: isize, ribbons_per_line: f64) -> Vec<(usize, String)> {
275	    let doc = cell_doc(flat);
276	    let rendered = render_page(line_len, ribbons_per_line, &doc);
277	    rendered
278	        .split('\n')
279	        .map(|line| {
280	            let indent = line.len() - line.trim_start_matches(' ').len();
281	            (indent, line[indent..].to_string())
282	        })
283	        .collect()
284	}
285	
286	/// Like [`wrap_cell_dot`] but with an explicit line length and ribbons-per-line.
287	pub fn wrap_cell_dot_lr(flat: &str, line_len: isize, ribbons_per_line: f64) -> String {
288	    let lines = layout_lines_lr(flat, line_len, ribbons_per_line);
289	    if lines.len() == 1 && lines[0].0 == 0 {
290	        return crate::render::escape_record(&lines[0].1);
291	    }
292	    let mut out = String::new();
293	    for (indent, content) in &lines {
294	        out.push_str(&"&nbsp;".repeat(*indent));
295	        out.push_str(&crate::render::escape_record(content));
296	        out.push_str("\\l");
297	    }
298	    out
299	}
