301	/// Render a cell's flat text into the exact graphviz record-label bytes at the
302	/// given fit **budget** (ribbon): a single escaped line when the flat width ≤
303	/// `budget`, otherwise each physical line prefixed by its `&nbsp;` indent,
304	/// escaped, and terminated by `\l` (trailing `\l` included), per BEHAVIOR.md §3f.
305	/// The layout is computed on the UN-escaped text (so `<`/`>` count one column
306	/// each, matching the reference), and escaping is applied afterwards. Wrapping is
307	/// ragged (line length = 1.5·budget; see [`RIBBONS`]).
308	pub fn wrap_cell_dot(flat: &str, budget: isize) -> String {
309	    let lines = layout_lines(flat, budget);
310	    if lines.len() == 1 && lines[0].0 == 0 {
311	        return crate::render::escape_record(&lines[0].1);
312	    }
313	    let mut out = String::new();
314	    for (indent, content) in &lines {
315	        out.push_str(&"&nbsp;".repeat(*indent));
316	        out.push_str(&crate::render::escape_record(content));
317	        out.push_str("\\l");
318	    }
319	    out
320	}
